    # -------------------------------------------------------------------------
    # LOCK: Generate lock files from input specifications
    # -------------------------------------------------------------------------
    def lock(self):
        """
        Generate lock files with pinned versions and hashes.

        For pip backend:
            - Reads requirements.in → generates requirements.txt
            - Reads requirements-dev.in → generates requirements-dev.txt
            - Includes SHA-256 hashes for each package
            - Resolves all transitive dependencies

        For Poetry backend:
            - Runs `poetry lock` to generate/update poetry.lock
            - Resolves all dependencies from pyproject.toml

        The lock file guarantees:
            1. Exact same versions installed everywhere
            2. Hash verification prevents tampered packages
            3. Complete dependency tree is captured
        """
        print(f"\n🔒 Generating lock files ({self.backend.value} backend)\n")

        if self.backend == Backend.PIP:
            self._lock_pip()
        else:
            self._lock_poetry()

        print("\n✅ Lock files generated successfully!")
        print("   Commit the lock files to version control.")

    def _lock_pip(self):
        """Generate lock files using pip-compile."""
        settings = self.config.get("settings", {})
        generate_hashes = settings.get("generate_hashes", True)
        annotate = settings.get("annotate", True)
        allow_unsafe = settings.get("allow_unsafe", False)

        # Lock production dependencies
        req_in = self.project_dir / "requirements.in"
        if req_in.exists():
            print("  📦 Locking production dependencies...")
            cmd = [
                "pip-compile",
                "--output-file=requirements.txt",
                "--strip-extras",
                "--no-emit-index-url",
            ]
            if generate_hashes:
                cmd.append("--generate-hashes")
            if annotate:
                cmd.append("--annotate")
            if allow_unsafe:
                cmd.append("--allow-unsafe")
            cmd.append("requirements.in")

            self._run_command(cmd)
            self._prepend_lock_header("requirements.txt")

            lock_hash = self._compute_file_hash(self.project_dir / "requirements.txt")
            print(f"  ✓ requirements.txt generated (hash: {lock_hash[:12]}...)")
        else:
            print("  ⚠ requirements.in not found, skipping production lock")

        # Lock development dependencies
        req_dev_in = self.project_dir / "requirements-dev.in"
        if req_dev_in.exists():
            print("\n  📦 Locking development dependencies...")
            cmd = [
                "pip-compile",
                "--output-file=requirements-dev.txt",
                "--strip-extras",
                "--no-emit-index-url",
            ]
            if generate_hashes:
                cmd.append("--generate-hashes")
            if annotate:
                cmd.append("--annotate")
            if allow_unsafe:
                cmd.append("--allow-unsafe")
            cmd.append("requirements-dev.in")

            self._run_command(cmd)
            self._prepend_lock_header("requirements-dev.txt")

            lock_hash = self._compute_file_hash(self.project_dir / "requirements-dev.txt")
            print(f"  ✓ requirements-dev.txt generated (hash: {lock_hash[:12]}...)")
        else:
            print("  ⚠ requirements-dev.in not found, skipping dev lock")

    def _lock_poetry(self):
        """Generate lock file using Poetry."""
        print("  📦 Locking all dependencies...")
        self._run_command(["poetry", "lock", "--no-update"])
        lock_hash = self._compute_file_hash(self.project_dir / "poetry.lock")
        print(f"  ✓ poetry.lock generated (hash: {lock_hash[:12]}...)")

    def _prepend_lock_header(self, filename: str):
        """Add metadata header to pip lock files."""
        filepath = self.project_dir / filename
        if not filepath.exists():
            return

        metadata = self._get_metadata()
        header = (
            f"#\n"
            f"# This file is autogenerated by dependency_manager.py\n"
            f"# Do not edit manually. Update the .in file and re-run:\n"
            f"#   python dependency_manager.py lock\n"
            f"#\n"
            f"# Generated: {metadata.generated_at}\n"
            f"# Python:    {metadata.python_version}\n"
            f"# Platform:  {metadata.platform}\n"
            f"#\n"
        )

        content = filepath.read_text()
        # Only add header if not already present
        if "autogenerated by dependency_manager" not in content:
            filepath.write_text(header + content)

    # -------------------------------------------------------------------------
    # UPDATE: Update specific or all dependencies
